;\n\nconst lines = msg.split(''\\n'').map(line => line.trim()).filter(Boolean);\n\nlet customer_name = '''';\nlet tracking_number = '''';\nlet hub_name = '''';\nlet store_name = '''';\nlet item_description = '''';\n\nfor (const line of lines) {\n  const lower = line.toLowerCase();\n\n  if (lower.startsWith(''nama:'')) {\n    customer_name = line.split('':'').slice(1).join('':'').trim();\n  } else if (lower.startsWith(''resi:'')) {\n    tracking_number = line.split('':'').slice(1).join('':'').trim();\n  } else if (lower.startsWith(''hub:'')) {\n    hub_name = line.split('':'').slice(1).join('':'').trim();\n  } else if (lower.startsWith(''toko:'')) {\n    store_name = line.split('':'').slice(1).join('':'').trim();\n  } else if (lower.startsWith(''barang:'')) {\n    item_description = line.split('':'').slice(1).join('':'').trim();\n  }\n}\n\nreturn [\n  {\n    json: {\n      phone: sanitized_phone,\n      ...$json,\n      customer_name,\n      tracking_number,\n      hub_name,\n      store_name,\n      item_description\n    }\n  }\n];\n"}, "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [512, -192], "id": "087b3733-9ac2-4e75-9060-f478bbe490fb", "name": "Parse RESI"}, {"parameters": {"method": "POST", "url": "http://172.17.0.1:3000/api/v1/nala/intake", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-nala-api-key", "value": "NalaWarekCargo2026_SecureM2M_Secret"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "specifyBody": "json", "jsonBody": "={\n  \"phone\": \"{{ $json[''phone''] }}\",\n  \"customer_name\": \"{{ $json[''customer_name''] }}\",\n  \"tracking_number\": \"{{ $json[''tracking_number''] }}\",\n  \"hub_name\": \"{{ $json[''hub_name''] }}\",\n  \"store_name\": \"{{ $json[''store_name''] }}\",\n  \"item_description\": \"{{ $json[''item_description''] }}\"\n}", "options": {}}, "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.4, "position": [762, -192], "id": "aaaaaa-1111", "name": "Call API Intake Internal"}, {"parameters": {"method": "POST", "url": "https://sby.wablas.com/api/send-message", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "Authorization", "value": "h4fTIwq0YQYhnFDi29f8kRrYCKXy306gxZ5AzJ4LM3lkW9J9B4Pbe0i"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "specifyBody": "json", "jsonBody": "={\n  \"phone\": \"{{ $node[''Parse RESI''].json[''phone''] }}\",\n  \"message\": \"{{ $json.human_message }}\"\n}", "options": {}}, "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.4, "position": [1012, -192], "id": "bbbbbb-2222", "name": "Wablas Response Sender"}]'::json, 
